import time
import jwt
import httpx

def get_github_app_token(app_id: int, private_key_pem: str) -> str:
    """Generate a short-lived JWT for GitHub App authentication."""
    now = int(time.time())
    payload = {
        "iat": now - 60,   # issued-at (60s slack for clock drift)
        "exp": now + 600,  # expires in 10 minutes
        "iss": app_id
    }
    return jwt.encode(payload, private_key_pem, algorithm="RS256")

def get_installation_token(app_jwt: str, installation_id: int) -> str:
    headers = {
        "Authorization": f"Bearer {app_jwt}",
        "Accept": "application/vnd.github+json"
    }
    resp = httpx.post(
        f"https://api.github.com/app/installations/{installation_id}/access_tokens",
        headers=headers
    )
    resp.raise_for_status()
    return resp.json()["token"]

def list_pull_requests(token: str, owner: str, repo: str):
    headers = {
        "Authorization": f"Bearer {token}",
        "Accept": "application/vnd.github+json"
    }
    resp = httpx.get(
        f"https://api.github.com/repos/{owner}/{repo}/pulls",
        headers=headers,
        params={"state": "open", "per_page": 20}
    )
    resp.raise_for_status()
    return resp.json()
